// Validate restaurant_id is a valid UUID
const restaurantId = $input.first().json.restaurant_id;

if (!restaurantId) {
  throw new Error('restaurant_id is required');
}

// Basic UUID format check
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(restaurantId)) {
  throw new Error('Invalid UUID format for restaurant_id');
}

return { restaurant_id: restaurantId };

// Merge all brand data into single object
const profile = $('Fetch Restaurant Profile').first().json;
const brandDna = $('Fetch Brand DNA').first().json;
const brandVisual = $('Fetch Brand Visual').first().json;

const brandMemory = {
  restaurant_id: profile.id || null,
  profile: profile || {},
  brand_dna: brandDna || {},
  brand_visual: brandVisual || {}
};

return brandMemory;

// Create text summary for prompt injection
const data = $input.first().json;
const profile = data.profile || {};
const dna = data.brand_dna || {};

const parts = [];

if (profile.name) parts.push(`Restaurant: ${profile.name}`);
if (profile.cuisine_type && profile.cuisine_type.length > 0) parts.push(profile.cuisine_type.join(', '));
if (profile.ambiance && profile.ambiance.length > 0) parts.push(`Ambiance: ${profile.ambiance.join(', ')}`);
if (profile.signature_dishes && profile.signature_dishes.length > 0) parts.push(`Plats signatures: ${profile.signature_dishes.join(', ')}`);
if (dna.tone && dna.tone.length > 0) parts.push(`Ton: ${dna.tone.join(', ')}`);
if (dna.vocabulary_preferred && dna.vocabulary_preferred.length > 0) parts.push(`Vocabulaire préféré: ${dna.vocabulary_preferred.join(', ')}`);
if (dna.vocabulary_forbidden && dna.vocabulary_forbidden.length > 0) parts.push(`Mots interdits: ${dna.vocabulary_forbidden.join(', ')}`);
if (dna.emojis_allowed && dna.emojis_allowed.length > 0) parts.push(`Emojis: ${dna.emojis_allowed.join(' ')}`);
if (dna.hashtags_primary && dna.hashtags_primary.length > 0) parts.push(`Hashtags: ${dna.hashtags_primary.join(', ')}`);
if (dna.content_pillars && dna.content_pillars.length > 0) parts.push(`Piliers: ${dna.content_pillars.join(', ')}`);
if (dna.target_audience) parts.push(`Audience: ${dna.target_audience}`);
if (dna.unique_selling_points && dna.unique_selling_points.length > 0) parts.push(`Différenciateurs: ${dna.unique_selling_points.join(', ')}`);

const summary = parts.join('. ') + '.';

return { ...data, summary };

// Format final output
const data = $input.first().json;

return {
  brand_dna: data.brand_dna || {},
  brand_visual: data.brand_visual || {},
  profile: data.profile || {},
  summary: data.summary || ''
};

